import './TextArea.scss';

import { classNames } from ':helpers/classnames';
import { useCombinedRef } from ':helpers/use-combined-ref';
import { textarea } from '@beeline/design-tokens/js/tokens';
import type { InputEvent } from 'react';
import React, { useEffect, useRef, useState } from 'react';
import type { MarginTextarea, TextAreaProps } from './TextArea.types';

// переводим стрингу из токенов в число
const marginToString = (margin: string): number => Number.parseInt(margin);

// считаем отступы из токенов
const calculateMargin = (): MarginTextarea => {
	const marginBottom: number = marginToString(textarea.textareaTextMarginBottom);
	return {
		medium: marginToString(textarea.textareaMediumWithoutLabelTextMarginTop) + marginBottom,
		mediumLabel: marginToString(textarea.textareaMediumLabelMarginTop) + marginBottom,
		small: marginToString(textarea.textareaSmallWithoutLabelTextMarginTop) + marginBottom,
		smallLabel: marginToString(textarea.textareaSmallLabelMarginTop) + marginBottom,
	};
};
// считаем отступы из токенов
const textareaMargin: MarginTextarea = calculateMargin();

export const TextArea = React.forwardRef<HTMLTextAreaElement, TextAreaProps>(
	(
		{
			label,
			size = 'medium',
			placeholder,
			className,
			id,
			textareaId,
			textareaClassName,
			fullWidth = false,
			error = false,
			helperText,
			disabled = false,
			autoHeight = false,
			dataTestId = 'TextArea',
			maxHeight,
			helperPosition = 'block',
			...props
		},
		ref,
	) => {
		const textareaRef = useRef<HTMLTextAreaElement | null>(null);
		const textAreaCombineRef = useCombinedRef(ref, textareaRef);

		const placeholderValue = placeholder || ' ';
		// дефолтное значение делаем уникальным с помощью рандома
		// если значение будет не уникальным, то при фокусе на лейбле произойдет фокус на первом элементе с подходящим айди
		const [_textareaId, setTextareaId] = useState<string>(textareaId);

		useEffect(() => {
			setTextareaId(textareaId || 'dsb_textfield-id-' + Math.random());
		}, [textareaId]);

		const showBlock = helperPosition === 'block';
		const showAbs = helperText && helperPosition === 'absolute';

		const handleClick = (): void => {
			textareaRef.current?.focus();
		};

		// считаем  максимальный размер текстарии
		useEffect(() => {
			if (textareaRef.current) {
				let currentMaxHeight = 'none';
				textareaRef.current.style.height = 'auto';
				if (autoHeight) {
					calculateHeight();
				}
				if (maxHeight) {
					const standartHeight = marginToString(
						size === 'medium' ? textarea.textareaMediumHeight : textarea.textareaSmallHeight,
					);
					const _maxHeight = Math.max(maxHeight, standartHeight);
					const key = size + (label ? 'Label' : '');
					currentMaxHeight = _maxHeight - textareaMargin[key] + 'px';
				}
				textareaRef.current.style.maxHeight = currentMaxHeight;
			}
		}, [autoHeight, label, maxHeight, size]);

		const onInputChange = (event: InputEvent<HTMLTextAreaElement>) => {
			props.onInput?.(event);
			if (autoHeight) {
				calculateHeight();
			}
		};

		const calculateHeight = () => {
			textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
		};

		return (
			<div
				data-testid={dataTestId}
				className={classNames(
					'dsb_textarea-wrapper',
					{
						'dsb_textarea-wrapper--disabled': disabled,
					},
					showAbs && 'dsb_textarea-wrapper--relative',
				)}
			>
				<div
					id={id}
					onClick={handleClick}
					className={classNames([
						'dsb_textarea-root',
						`dsb_textarea-root--${size}`,
						error && 'dsb_textarea-root--error',
						label && 'dsb_textarea-root--labeled',
						fullWidth && 'dsb_textarea-root--fullwidth',
						className,
					])}
				>
					<textarea
						ref={textAreaCombineRef}
						id={_textareaId}
						data-testid={dataTestId + '-textarea'}
						disabled={disabled}
						placeholder={placeholderValue}
						onInput={onInputChange}
						className={classNames(
							'dsb_textarea',
							`dsb_textarea--${size}`,
							error && 'dsb_textarea--error',
							label && 'dsb_textarea--labeled',
							textareaClassName,
						)}
						aria-invalid={error}
						{...props}
					/>
					<div className={classNames('dsb_textarea-borders')} />
					{label && (
						<label htmlFor={_textareaId} className="dsb_textarea-label" data-testid={dataTestId + '-label'}>
							{label}
						</label>
					)}
					{showAbs && (
						<div
							className={classNames(
								'dsb_textarea-helper-text',
								error && 'dsb_textarea-helper-text--error',
								showAbs && 'dsb_textarea-helper-text--absolute',
							)}
						>
							{helperText}
						</div>
					)}
				</div>

				{showBlock && (
					<div className="dsb_textarea-helper-text-block-wrapper">
						<sup className={classNames('dsb_textarea-helper-text', error && 'dsb_textarea-helper-text--error')}>
							{helperText}
						</sup>
					</div>
				)}
			</div>
		);
	},
);
